def solve():
    x = 1
    t = 0

    while x != 2090:
        # Find p(k) - smallest prime that does not divide x
        k = x
        p_k = 2
        while k % p_k == 0:
            p_k = next_prime(p_k)

        # Find X(k)
        if p_k == 2:
            X_k = 1
        else:
            X_k = 1
            prime = 2
            while prime < p_k:
                X_k *= prime
                prime = next_prime(prime)

        # Compute next x
        x = (x * p_k) // X_k
        t += 1

    return t

def next_prime(n):
    if n < 2:
        return 2
    candidate = n + 1
    while True:
        if is_prime(candidate):
            return candidate
        candidate += 1

def is_prime(n):
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return False
    return True
