# Constants
IP_REGEX = r'[0-9]+(?:\.[0-9]+){3}'

def task_func(API_URL):
    try:
        with urllib.request.urlopen(API_URL) as response:
            if response.getcode() != 200:
                raise Exception(f"HTTP error: {response.getcode()}")
            data = response.read().decode('utf-8')
            # Try to extract IP from JSON response
            try:
                json_data = json.loads(data)
                # Look for IP in common JSON response patterns
                if isinstance(json_data, dict):
                    for key, value in json_data.items():
                        if isinstance(value, str) and re.match(IP_REGEX, value):
                            return value
                elif isinstance(json_data, str) and re.match(IP_REGEX, json_data):
                    return json_data
            except json.JSONDecodeError:
                # If not JSON, try to extract IP from plain text
                match = re.search(IP_REGEX, data)
                if match:
                    return match.group()
            # If no IP found in the expected format
            raise Exception("No valid IP address found in response")
    except Exception as e:
        raise Exception(f"API request failed: {str(e)}")
