import subprocess
import os
import signal
import time

def task_func(process_name: str) -> int:
    stopped_count = 0
    try:
        # Get list of processes with the given name using pgrep
        result = subprocess.run(['pgrep', process_name], capture_output=True, text=True, check=False)
        if result.returncode == 0:
            pids = result.stdout.strip().split('\n')
            for pid in pids:
                if pid:
                    try:
                        os.kill(int(pid), signal.SIGTERM)
                        stopped_count += 1
                    except ProcessLookupError:
                        # Process already terminated
                        continue
            # Wait for processes to terminate
            time.sleep(1)
    except Exception:
        pass

    return stopped_count
