import socket
import select
import queue
from datetime import datetime, timedelta

def task_func(
    server_address="localhost", server_port=12345, buffer_size=1024, run_duration=5
):
    # Create a TCP socket
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server_socket.setblocking(False)

    # Allow reuse of address
    server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)

    # Bind the socket to the address and port
    server_socket.bind((server_address, server_port))

    # Listen for incoming connections
    server_socket.listen(5)

    # Set up the selector for monitoring sockets
    inputs = [server_socket]
    outputs = []
    message_queues = {}

    # Track start time
    start_time = datetime.now()
    end_time = start_time + timedelta(seconds=run_duration)

    status_message = f"Echo server started on {server_address}:{server_port} - Running for {run_duration} seconds\n"

    try:
        while datetime.now() < end_time:
            # Wait for any of the sockets to be ready for I/O
            readable, writable, exceptional = select.select(inputs, outputs, inputs, 1.0)

            # Handle readable sockets
            for s in readable:
                if s is server_socket:
                    # New connection
                    connection, client_address = s.accept()
                    connection.setblocking(False)
                    inputs.append(connection)
                    message_queues[connection] = queue.Queue()
                    status_message += f"New connection from {client_address}\n"
                else:
                    # Existing connection
                    try:
                        data = s.recv(buffer_size)
                        if data:
                            # Append current time to received data
                            current_time = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                            response = f"{data.decode('utf-8')} | Server time: {current_time}\n"
                            message_queues[s].put(response.encode('utf-8'))
                            if s not in outputs:
                                outputs.append(s)
                        else:
                            # Client disconnected
                            if s in outputs:
                                outputs.remove(s)
                            inputs.remove(s)
                            s.close()
                            del message_queues[s]
                            status_message += f"Connection closed with {s.getpeername()}\n"
                    except Exception as e:
                        status_message += f"Error reading from {s.getpeername()}: {e}\n"
                        if s in outputs:
                            outputs.remove(s)
                        if s in inputs:
                            inputs.remove(s)
                        s.close()
                        if s in message_queues:
                            del message_queues[s]

            # Handle writable sockets
            for s in writable:
                try:
                    if not message_queues[s].empty():
                        message = message_queues[s].get_nowait()
                        sent = s.send(message)
                        if sent < len(message):
                            # Not all data sent, put back in queue
                            remaining = message[sent:]
                            message_queues[s].put(remaining)
                    else:
                        # No more data to send, remove from outputs
                        outputs.remove(s)
                except Exception as e:
                    status_message += f"Error writing to {s.getpeername()}: {e}\n"
                    if s in outputs:
                        outputs.remove(s)
                    if s in inputs:
                        inputs.remove(s)
                    s.close()
                    if s in message_queues:
                        del message_queues[s]

            # Handle exceptional conditions
            for s in exceptional:
                status_message += f"Exceptional condition on {s.getpeername()}\n"
                if s in outputs:
                    outputs.remove(s)
                if s in inputs:
                    inputs.remove(s)
                s.close()
                if s in message_queues:
                    del message_queues[s]

    except Exception as e:
        status_message += f"Server error: {e}\n"
    finally:
        # Clean up
        server_socket.close()
        for s in inputs:
            if s != server_socket:
                s.close()
        for s in outputs:
            s.close()
        status_message += f"Echo server stopped after {run_duration} seconds\n"

    return status_message
```

