import os
import shutil

def task_func(path, delimiter="/"):
    if not isinstance(path, str):
        raise ValueError("path must be a string")
    if not path:
        raise ValueError("path cannot be empty")
    if not isinstance(delimiter, str) or len(delimiter) != 1:
        raise ValueError("delimiter must be a single character")

    components = path.split(delimiter)
    if any(comp in ('', '.', '..') for comp in components):
        raise ValueError("path contains invalid components")

    result = []
    current_path = ""
    for comp in components:
        current_path = os.path.join(current_path, comp) if current_path else comp

        if not os.path.exists(current_path):
            raise FileNotFoundError(f"Path does not exist: {current_path}")

        if not os.path.isdir(current_path):
            raise ValueError(f"Path is not a directory: {current_path}")

        try:
            stat = shutil.disk_usage(current_path)
            usage = {
                'total': stat.total,
                'used': stat.used,
                'free': stat.free
            }
            result.append((comp, usage))
        except Exception as e:
            raise ValueError(f"Could not get disk usage for {current_path}: {str(e)}")

    return result
