from nltk.stem import PorterStemmer
from collections import Counter
STEMMER = PorterStemmer()
def task_func(content):
    # Split the content into words, keeping punctuation attached to words
    words = re.findall(r'\b[a-zA-Z]+\b', content.lower())

    # If there are no words, return empty dict
    if not words:
        return {}

    # Stem all words except the last one
    stems = []
    for i, word in enumerate(words):
        if i == len(words) - 1:
            # Keep the last word unstemmed
            stems.append(word)
        else:
            stems.append(STEMMER.stem(word))

    # Count frequency of each stem
    return dict(Counter(stems))
