# Constants
DATA_TYPES = [str, int, float, list, tuple, dict, set]

def task_func(rows, columns):
    data = {}
    for col_idx in range(columns):
        col_name = f'col{col_idx}'
        data_type = choice(DATA_TYPES)

        if data_type == str:
            data[col_name] = [''.join(choice('abcdefghijklmnopqrstuvwxyz') for _ in range(5)) for _ in range(rows)]
        elif data_type == int:
            data[col_name] = [np.random.randint(0, 10) for _ in range(rows)]
        elif data_type == float:
            data[col_name] = [float(np.random.randint(0, 10)) for _ in range(rows)]
        elif data_type == list:
            data[col_name] = [np.random.randint(0, 10, size=np.random.randint(1, 6)).tolist() for _ in range(rows)]
        elif data_type == tuple:
            data[col_name] = [tuple(np.random.randint(0, 10, size=np.random.randint(1, 6)).tolist()) for _ in range(rows)]
        elif data_type == dict:
            data[col_name] = []
            for _ in range(rows):
                size = np.random.randint(1, 6)
                keys = np.random.randint(0, 10, size=size)
                values = np.random.randint(0, 10, size=size)
                data[col_name].append(dict(zip(keys, values)))
        elif data_type == set:
            data[col_name] = []
            for _ in range(rows):
                size = np.random.randint(1, 6)
                values = np.random.randint(0, 10, size=size)
                data[col_name].append(set(values))

    # Ensure all values are hashable for DataFrame (convert sets to frozensets)
    if any(data_type == set for data_type in [choice(DATA_TYPES) for _ in range(columns)]):
        for col_name in data:
            if isinstance(data[col_name][0], set):
                data[col_name] = [frozenset(item) for item in data[col_name]]

    return pd.DataFrame(data)
