def check_sequence(text, patterns):
    if not patterns:
        return True

    pattern_idx = 0
    text_idx = 0

    while text_idx < len(text) and pattern_idx < len(patterns):
        pattern = patterns[pattern_idx]
        pattern_len = len(pattern)

        # Check if the current pattern matches at the current position
        if text_idx + pattern_len <= len(text) and text[text_idx:text_idx + pattern_len] == pattern:
            text_idx += pattern_len
            pattern_idx += 1
        else:
            # Try to find the pattern starting from the next character
            text_idx += 1

    # If we've matched all patterns, return True
    return pattern_idx == len(patterns)
