```python
def eulerian(n, m):
    if m >= n or m < 0:
        return 0
    if m == 0:
        return 1
    if n == 1:
        return 1

    # Use dynamic programming with memoization
    memo = {}

    def dp(n, m):
        if (n, m) in memo:
            return memo[(n, m)]
        if m >= n or m < 0:
            result = 0
        elif m == 0:
            result = 1
        elif n == 1:
            result = 1
        else:
            result = (n - m) * dp(n - 1, m - 1) + (m + 1) * dp(n - 1, m)
        memo[(n, m)] = result
        return result

    return dp(n, m)
```

