def sum_amicable_numbers(limit):
    def sum_of_divisors(n):
        total = 1
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                total += i
                if i != n // i:
                    total += n // i
        return total

    amicable_sum = 0
    seen = set()

    for num in range(2, limit + 1):
        if num in seen:
            continue

        sum_div = sum_of_divisors(num)
        if sum_div != num and sum_div <= limit:
            sum_div2 = sum_of_divisors(sum_div)
            if sum_div2 == num:
