```python
def solve_linear_diophantine(a, b, n):
    if a == 0 and b == 0:
        return None if n != 0 else (0, 0)

    if a == 0:
        if n % b == 0:
            return (0, n // b)
        else:
            return None

    if b == 0:
        if n % a == 0:
            return (n // a, 0)
        else:
            return None

    # Use extended Euclidean algorithm to find gcd and coefficients
    def extended_gcd(x, y):
        if x == 0:
            return y, 0, 1
        gcd, x1, y1 = extended_gcd(y % x, x)
        x_new = y1 - (y // x) * x1
        y_new = x1
        return gcd, x_new, y_new

    gcd, x0, y0 = extended_gcd(abs(a), abs(b))

    # Check if solution exists
    if n % gcd != 0:
        return None

    # Scale the solution
    factor = n // gcd
    x = x0 * factor
    y = y0 * factor

    # Adjust signs based on original a and b
    if a < 0:
        x = -x
    if b < 0:
        y = -y

    return (x, y)
```

