def nth_newman_shanks_williams_prime(n):
    if n < 1:
        return None

    count = 0
    k = 1

    while count < n:
        # Calculate the Newman-Shanks-Williams number: (2^k + 1) * (2^k - 1) + 1
        # This simplifies to 2^(2k) - 2^k + 1
        value = (2 ** k) * (2 ** k) - (2 ** k) + 1

        # Check if the value is prime
        if value > 1:
            is_prime = True
            if value == 2:
                pass
            elif value % 2 == 0:
                is_prime = False
            else:
                i = 3
                while i * i <= value:
                    if value % i == 0:
                        is_prime = False
                        break
                    i += 2

            if is_prime:
                count += 1
                if count == n:
                    return value

        k += 1
