def sum_even_index_binomial(n):
    sum_even_index_binomial = 0
    for k in range(0, n + 1, 2):
        # Calculate C(n, k) using the formula: n! / (k! * (n-k)!)
        # To avoid large factorials, use iterative computation
        if k == 0 or k == n:
            term = 1
        else:
            # Compute C(n, k) iteratively to avoid large factorials
            term = 1
            for i in range(min(k, n - k)):
                term = term * (n - i) // (i + 1)
        sum_even_index_binomial += term
    return sum_even_index_binomial
```

