def count_binary_sequences(n):
    count = 0

    def backtrack(pos, left_sum, right_sum):
        if pos == 2 * n:
            if left_sum == right_sum:
                nonlocal count
                count += 1
            return

        if pos < n:
            # First n positions
            backtrack(pos + 1, left_sum + 1, right_sum)  # place 1
            backtrack(pos + 1, left_sum, right_sum)      # place 0
        else:
            # Last n positions
            backtrack(pos + 1, left_sum, right_sum + 1)  # place 1
            backtrack(pos + 1, left_sum, right_sum)      # place 0

    backtrack(0, 0, 0)
    return count
```

