def set_leftmost_unset_bit(n):
    if n == 0:
        return 1

    # Find the position of the leftmost unset bit
    bit_pos = 0
    temp = n
    while temp > 0:
        if (temp & 1) == 0:
            break
        temp >>= 1
        bit_pos += 1

    # Set the leftmost unset bit
    return n | (1 << bit_pos)
