def tuple_intersection(tuple_list):
    if not tuple_list:
        return tuple()

    # Convert each tuple to a sorted tuple to handle order independence
    sorted_tuples = [tuple(sorted(t)) for t in tuple_list]

    # Find intersection by converting to sets
    result_set = set(sorted_tuples[0])
    for t in sorted_tuples[1:]:
        result_set &= set(t)

    # Convert back to sorted tuple
    return tuple(sorted(result_set))
```

