def min_swaps_to_convert(s1, s2):
    if len(s1) != len(s2):
        raise ValueError("Strings must be of the same length")

    # Count positions where bits differ
    diff_count = 0
    for i in range(len(s1)):
        if s1[i] != s2[i]:
            diff_count += 1

    # For binary strings, each swap can fix two mismatched positions
    # But only if the number of mismatches is even
    if diff_count % 2 != 0:
        raise ValueError("Cannot convert - odd number of differing positions")

    return diff_count // 2
