def bell_number(n):
    if n == 0:
        return 1
    if n == 1:
        return 1

    # Use dynamic programming to compute Bell numbers
    bell = [0] * (n + 1)
    bell[0] = 1

    for i in range(1, n + 1):
        bell[i] = 0
        for j in range(i):
            bell[i] += comb(i - 1, j) * bell[j]

    return bell[n]
