def rgb_to_hsv(rgb):
    r, g, b = rgb[0] / 255.0, rgb[1] / 255.0, rgb[2] / 255.0

    max_val = max(r, g, b)
    min_val = min(r, g, b)
    diff = max_val - min_val

    if max_val == 0:
        saturation = 0
    else:
        saturation = diff / max_val

    value = max_val

    if diff == 0:
        hue = 0
    else:
        if max_val == r:
            hue = (g - b) / diff
        elif max_val == g:
            hue = 2 + (b - r) / diff
        else:
            hue = 4 + (r - g) / diff

        hue *= 60
        if hue < 0:
            hue += 360

    return (hue, saturation, value)
```

