    n = len(arr)

    while left <= right:
        # If the array is already sorted (no rotation)
        if arr[left] <= arr[right]:
            return left

        mid = (left + right) // 2

        # Check if mid is the pivot point (smallest element)
        if mid > 0 and arr[mid] < arr[mid - 1]:
