import subprocess
import psutil
import time
import os

def task_func(script_path: str, timeout=10) -> dict:
    if not os.path.exists(script_path):
        raise FileNotFoundError(f"Script not found: {script_path}")

    if not os.access(script_path, os.X_OK):
        raise PermissionError(f"Script is not executable: {script_path}")

    # Start the script in a subprocess
    process = subprocess.Popen(['bash', script_path], stdout=subprocess.PIPE, stderr=subprocess.PIPE)

    # Create a psutil process object for the subprocess
    try:
        proc = psutil.Process(process.pid)
    except psutil.NoSuchProcess:
        return {'CPU Usage': 0, 'Memory Usage': 0}

    cpu_usage = 0.0
    memory_usage = 0.0
    start_time = time.time()

    try:
        while True:
            # Check if process is still running
            if not proc.is_running():
                break

            # Check if process has become a zombie
            if proc.status() == psutil.STATUS_ZOMBIE:
                break

            # Get current CPU usage (as percentage)
            try:
                cpu_percent = proc.cpu_percent(interval=0.1)
                cpu_usage += cpu_percent
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                break

            # Get current memory usage (RSS in bytes)
            try:
                memory_info = proc.memory_info()
                memory_usage += memory_info.rss
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                break

            # Check timeout
            if time.time() - start_time > timeout:
                break

            # Small delay to avoid busy waiting
            time.sleep(0.05)

    except (psutil.NoSuchProcess, psutil.AccessDenied):
        pass
    finally:
        # Ensure process is terminated if it's still running
        try:
            if proc.is_running():
                proc.terminate()
                try:
                    proc.wait(timeout=2)
                except psutil.TimeoutExpired:
                    proc.kill()
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            pass

    return {
        'CPU Usage': round(cpu_usage, 2),
        'Memory Usage': int(memory_usage)
    }
