def task_func(data, mapping):
    # Create a copy to avoid modifying the original DataFrame
    df = data.copy()

    # Compile regex pattern for all acronyms to improve performance
    acronyms = list(mapping.keys())
    pattern = '|'.join(re.escape(acronym) for acronym in acronyms)
    regex = re.compile(pattern)

    # Function to replace acronyms in a single string
    def replace_acronyms(text):
        if not isinstance(text, str):
            return text

        def replace_match(match):
            return mapping[match.group()]

        return regex.sub(replace_match, text)

    # Apply the replacement to all string cells in the DataFrame
    return df.applymap(replace_acronyms)
