import os
import re
from pathlib import Path

def task_func(dir_path: str, predicates: list) -> dict:
    if not predicates:
        raise ValueError("No valid predicates provided.")

    dir_path = Path(dir_path)
    if not dir_path.exists():
        raise FileNotFoundError(f"Directory does not exist: {dir_path}")
    if not dir_path.is_dir():
        raise FileNotFoundError(f"Path is not a directory: {dir_path}")

    # Deduplicate predicates while preserving order
    seen = set()
    unique_predicates = []
    for pred in predicates:
        if pred not in seen:
            seen.add(pred)
            unique_predicates.append(pred)

    results = {}
    for item in dir_path.iterdir():
        item_name = item.name
        item_results = {}

        for pred in unique_predicates:
            try:
                if isinstance(pred, str):
                    # Treat string as regex pattern
                    item_results[pred] = bool(re.fullmatch(pred, item_name))
                elif callable(pred):
                    # Treat as function predicate
                    item_results[pred] = pred(item_name)
                else:
                    # Try to call as function
                    item_results[pred] = pred(item_name)
            except Exception:
                # If predicate fails, consider it as False
                item_results[pred] = False

        results[item_name] = item_results

    return results
