import xml.etree.ElementTree as ET
import csv

def task_func(xml_content, output_csv_path):
    try:
        # Parse the XML content
        root = ET.fromstring(xml_content)

        # Check if there are any elements
        if root is None:
            raise ValueError("XML content is empty or invalid")

        # Extract headers from the first element's attributes and child elements
        headers = set()

        # Add attributes as headers
        if len(root) > 0:
            first_element = root[0]
            headers.update(first_element.attrib.keys())

            # Add child elements as headers if they exist
            for child in first_element:
                headers.add(child.tag)
        else:
            # If root has no children, just use attributes from root
            headers.update(root.attrib.keys())

        # Convert set to list for consistent ordering
        headers = sorted(list(headers))

        # Write to CSV file
        with open(output_csv_path, 'w', newline='', encoding='utf-8') as csvfile:
            writer = csv.DictWriter(csvfile, fieldnames=headers)
            writer.writeheader()

            # Process each element in the XML
            for element in root:
                row = {}

                # Add attributes to the row
                for attr_name, attr_value in element.attrib.items():
                    row[attr_name] = attr_value

                # Add child elements to the row
                for child in element:
                    if child.tag not in row:
                        row[child.tag] = child.text or ""
                    else:
                        # Handle duplicate tags by appending to existing key
                        if isinstance(row[child.tag], str):
                            row[child.tag] = f"{row[child.tag]},{child.text or ''}"
                        else:
                            row[child.tag] = f"{row[child.tag]},{child.text or ''}"

                writer.writerow(row)

    except ET.ParseError as e:
        raise ET.ParseError(f"Failed to parse XML content: {str(e)}")
    except IOError as e:
        raise IOError(f"Failed to write to CSV file at {output_csv_path}: {str(e)}")
