import subprocess
import csv
import os

def task_func(commands_file_path, output_dir_path):
    if not os.path.exists(commands_file_path):
        raise FileNotFoundError(f"Commands file not found: {commands_file_path}")

    if not os.path.exists(output_dir_path):
        os.makedirs(output_dir_path)

    output_files = []

    with open(commands_file_path, 'r') as csvfile:
        reader = csv.reader(csvfile)
        for idx, row in enumerate(reader):
            if not row:
                continue

            command = row[0].strip()
            output_file_path = os.path.join(output_dir_path, f'command_{idx}_output.txt')

            try:
                result = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=300)

                with open(output_file_path, 'w') as output_file:
                    if result.stdout:
                        output_file.write(result.stdout)
                    if result.stderr:
                        output_file.write(result.stderr)

            except subprocess.TimeoutExpired:
                with open(output_file_path, 'w') as output_file:
                    output_file.write(f"Command timed out after 300 seconds: {command}\n")
            except Exception as e:
                with open(output_file_path, 'w') as output_file:
                    output_file.write(f"Command execution failed: {str(e)}\n")

            output_files.append(output_file_path)

    return output_files
