                    ['ping', '-c', '1', '-W', '1', ip_str],
                    stderr=subprocess.DEVNULL,
                    timeout=2
                )
                active_ips[ip_str] = True
            except subprocess.CalledProcessError:
                # This exception should be raised as specified
                raise
            except subprocess.TimeoutExpired:
                active_ips[ip_str] = False
    except Exception as e:
        raise e

    return active_ips
