import pandas as pd
from collections import Counter

def task_func(file_name):
    try:
        df = pd.read_csv(file_name)
    except pd.errors.EmptyDataError:
        return {}

    if df.empty:
        return {}

    result = {}
    for col in df.columns:
        # Drop NaN values for counting
        values = df[col].dropna()
        if values.empty:
            result[col] = None
            continue

        # Count occurrences
        counter = Counter(values)

        # Find max count
        max_count = max(counter.values())

        # Get all values with max count and sort alphabetically
        most_common_values = [val for val, count in counter.items() if count == max_count]
        most_common_values.sort()

        # Take the first (alphabetically smallest) value
        result[col] = most_common_values[0]

    return result
