import collections
import json
import os

def task_func(directory_path: str) -> dict:
    key_counter = collections.Counter()

    # Iterate through all files in the directory
    for filename in os.listdir(directory_path):
        file_path = os.path.join(directory_path, filename)

        # Check if it's a file and has .json extension
        if os.path.isfile(file_path) and filename.lower().endswith('.json'):
            try:
                with open(file_path, 'r', encoding='utf-8') as file:
                    data = json.load(file)

                    # Recursively count keys in nested structures
                    def count_keys(obj):
                        if isinstance(obj, dict):
                            for key in obj.keys():
                                key_counter[key] += 1
                            for value in obj.values():
                                count_keys(value)
                        elif isinstance(obj, list):
                            for item in obj:
                                count_keys(item)

                    count_keys(data)

            except (json.JSONDecodeError, IOError) as e:
                # Skip files that can't be read or are not valid JSON
                continue

    return dict(key_counter)
