import json
import requests
import chardet

# Constants
API_URL = "http://api.example.com/data"

def task_func(url=API_URL, from_encoding=None, to_encoding="utf8"):
    try:
        response = requests.get(url, timeout=5)
        response.raise_for_status()

        content = response.content

        # Return empty dict if content is empty
        if not content:
            return {}

        # Detect encoding if not provided
        if from_encoding is None:
            detected = chardet.detect(content)
            if detected['encoding'] is None:
                raise ValueError("Unable to detect encoding for non-empty content")
            from_encoding = detected['encoding']

        # Decode using detected or provided encoding
        try:
            decoded_content = content.decode(from_encoding)
        except (UnicodeDecodeError, LookupError):
            # If decoding fails, try common encodings
            for enc in ['utf-8', 'latin1', 'iso-8859-1']:
                try:
                    decoded_content = content.decode(enc)
                    from_encoding = enc
                    break
                except UnicodeDecodeError:
                    continue
            else:
                raise ValueError("Unable to detect encoding for non-empty content")

        # Re-encode to specified encoding (default: utf8)
        encoded_content = decoded_content.encode(to_encoding)

        # Parse as JSON
        return json.loads(encoded_content.decode(to_encoding))

    except requests.exceptions.RequestException as e:
        # Handle network-related errors
        raise RuntimeError(f"Failed to fetch data from {url}: {e}")
    except json.JSONDecodeError as e:
        # Handle JSON parsing errors
        raise ValueError(f"Failed to parse JSON: {e}")
